// Fetch all active marketplace listings joined with their connection credentials.
// Two-phase approach:
//   1. Fetch active listings with connection_id + marketplace
//   2. Fetch unique connection credentials from decrypted view
// Returns flat list: one item per listing with embedded access_token.

const Sentry = require('@sentry/node');
const https = require('https');

const SUPABASE_URL = $env.SUPABASE_URL;
const SUPABASE_KEY = $env.SUPABASE_SERVICE_ROLE_KEY;

async function supabaseGet(table, queryParams) {
  const params = new URLSearchParams(queryParams);
  const url = `${SUPABASE_URL}/rest/v1/${table}?${params.toString()}`;

  return new Promise((resolve, reject) => {
    const req = https.request(url, {
      method: 'GET',
      headers: {
        'apikey': SUPABASE_KEY,
        'Authorization': `Bearer ${SUPABASE_KEY}`,
        'Content-Type': 'application/json',
      }
    }, (res) => {
      let body = '';
      res.on('data', (chunk) => body += chunk);
      res.on('end', () => {
        try { resolve(JSON.parse(body)); } catch (e) { reject(new Error(`Parse error: ${body}`)); }
      });
    });
    req.on('error', reject);
    req.end();
  });
}

try {
  // Phase 1: Fetch active listings
  const listings = await supabaseGet('shop_marketplace_listings', {
    select: 'id,external_listing_id,connection_id,marketplace,status',
    status: 'eq.active',
  });

  if (!Array.isArray(listings)) {
    throw new Error(`Unexpected listings response: ${JSON.stringify(listings)}`);
  }

  if (listings.length === 0) {
    Sentry.addBreadcrumb({ message: 'Status sync: no active listings found', level: 'info' });
    return [];
  }

  // Phase 2: Fetch unique connection credentials (decrypted)
  const uniqueConnectionIds = [...new Set(listings.map((l) => l.connection_id))];
  const connectionMap = {};

  for (const connId of uniqueConnectionIds) {
    const connections = await supabaseGet('shop_marketplace_connections_decrypted', {
      select: 'id,marketplace,access_token,token_expires_at,is_active',
      id: `eq.${connId}`,
      is_active: 'eq.true',
      limit: '1',
    });

    if (Array.isArray(connections) && connections.length > 0) {
      connectionMap[connId] = connections[0];
    }
  }

  Sentry.addBreadcrumb({
    message: `Status sync: ${listings.length} active listing(s), ${Object.keys(connectionMap).length} connection(s)`,
    level: 'info',
  });

  // Combine: one flat item per listing with embedded credentials
  return listings
    .filter((listing) => {
      if (!listing.external_listing_id) return false; // skip unpublished
      const conn = connectionMap[listing.connection_id];
      if (!conn) return false; // skip if connection inactive or not found
      return true;
    })
    .map((listing) => {
      const conn = connectionMap[listing.connection_id];
      return {
        listing_id: listing.id,
        external_listing_id: listing.external_listing_id,
        connection_id: listing.connection_id,
        marketplace: listing.marketplace || conn.marketplace,
        current_db_status: listing.status,
        access_token: conn.access_token,
        token_expires_at: conn.token_expires_at,
      };
    });
} catch (err) {
  Sentry.captureException(err);
  await Sentry.flush(2000);
  throw err;
}

// OLX status check.
// Endpoint: GET /api/partner/adverts/{external_listing_id}
// OLX status → our DB status:
//   active/limited → 'active'
//   removed_by_user/disabled/moderated → 'removed' (mapped to 'expired' in DB per spec)
//   outdated → 'expired'
// Note: spec says 'removed'→'expired', following OLX_STATUS_MAP from adapter code.

const Sentry = require('@sentry/node');
const https = require('https');

const input = $input.first().json;

const isSandbox = $env.OLX_USE_SANDBOX === 'true';
const OLX_API = isSandbox
  ? 'https://www-sandbox.olx.pl/api/partner'
  : 'https://www.olx.pl/api/partner';

// OLX status map (mirrors adapter/olx.ts OLX_STATUS_MAP)
const OLX_STATUS_MAP = {
  active: 'active',
  limited: 'active',
  removed_by_user: 'expired',
  outdated: 'expired',
  disabled: 'expired',
  moderated: 'expired',
};

async function olxGet(path, token) {
  const url = `${OLX_API}${path}`;
  return new Promise((resolve, reject) => {
    const req = https.request(url, {
      method: 'GET',
      headers: {
        'Authorization': `Bearer ${token}`,
        'Content-Type': 'application/json',
        'Version': '2.0',
      },
    }, (res) => {
      let data = '';
      res.on('data', (chunk) => data += chunk);
      res.on('end', () => {
        try { resolve({ status: res.statusCode, body: JSON.parse(data) }); }
        catch (e) { resolve({ status: res.statusCode, body: data }); }
      });
    });
    req.on('error', reject);
    req.end();
  });
}

try {
  const result = await olxGet(`/adverts/${input.external_listing_id}`, input.access_token);

  if (result.status === 404) {
    // Listing no longer exists on OLX
    return {
      listing_id: input.listing_id,
      current_db_status: input.current_db_status,
      new_status: 'expired',
      status_changed: input.current_db_status !== 'expired',
      expires_at: null,
    };
  }

  if (result.status >= 400) {
    throw new Error(`OLX status check failed: HTTP ${result.status} — ${JSON.stringify(result.body)}`);
  }

  const olxStatus = result.body.status || 'unknown';
  const newStatus = OLX_STATUS_MAP[olxStatus] || 'expired';
  const expiresAt = result.body.valid_to || null;

  return {
    listing_id: input.listing_id,
    current_db_status: input.current_db_status,
    new_status: newStatus,
    status_changed: input.current_db_status !== newStatus,
    expires_at: expiresAt,
  };
} catch (err) {
  Sentry.captureException(new Error(`[OLX Status] listing ${input.listing_id}: ${err.message}`));
  await Sentry.flush(2000);
  return {
    listing_id: input.listing_id,
    current_db_status: input.current_db_status,
    sync_error: err.message,
  };
}

// Allegro status check.
// Endpoint: GET /sale/product-offers/{external_listing_id}
// Allegro publication.status → our DB status:
//   ACTIVE/ACTIVATING → 'active'
//   ENDED → 'expired'
//   INACTIVE → 'expired'
// Note: endpoint is product-offers (not sale/offers) — matches adapter code.

const Sentry = require('@sentry/node');
const https = require('https');

const input = $input.first().json;

const isSandbox = $env.ALLEGRO_USE_SANDBOX === 'true';
const ALLEGRO_API = isSandbox
  ? 'https://api.allegro.pl.allegrosandbox.pl'
  : 'https://api.allegro.pl';

const ALLEGRO_ACCEPT = 'application/vnd.allegro.public.v1+json';

// Allegro status map (mirrors adapter/allegro.ts ALLEGRO_STATUS_MAP)
const ALLEGRO_STATUS_MAP = {
  ACTIVE: 'active',
  ACTIVATING: 'active',
  INACTIVE: 'expired',
  ENDED: 'expired',
};

async function allegroGet(path, token) {
  const url = `${ALLEGRO_API}${path}`;
  return new Promise((resolve, reject) => {
    const req = https.request(url, {
      method: 'GET',
      headers: {
        'Authorization': `Bearer ${token}`,
        'Accept': ALLEGRO_ACCEPT,
        'Content-Type': ALLEGRO_ACCEPT,
      },
    }, (res) => {
      let data = '';
      res.on('data', (chunk) => data += chunk);
      res.on('end', () => {
        try { resolve({ status: res.statusCode, body: JSON.parse(data) }); }
        catch (e) { resolve({ status: res.statusCode, body: data }); }
      });
    });
    req.on('error', reject);
    req.end();
  });
}

try {
  const result = await allegroGet(`/sale/product-offers/${input.external_listing_id}`, input.access_token);

  if (result.status === 404) {
    // Listing no longer exists on Allegro
    return {
      listing_id: input.listing_id,
      current_db_status: input.current_db_status,
      new_status: 'expired',
      status_changed: input.current_db_status !== 'expired',
      expires_at: null,
    };
  }

  if (result.status >= 400) {
    throw new Error(`Allegro status check failed: HTTP ${result.status} — ${JSON.stringify(result.body)}`);
  }

  const publicationStatus = result.body.publication?.status || 'INACTIVE';
  const newStatus = ALLEGRO_STATUS_MAP[publicationStatus] || 'expired';
  const expiresAt = result.body.publication?.endingAt || null;

  return {
    listing_id: input.listing_id,
    current_db_status: input.current_db_status,
    new_status: newStatus,
    status_changed: input.current_db_status !== newStatus,
    expires_at: expiresAt,
  };
} catch (err) {
  Sentry.captureException(new Error(`[Allegro Status] listing ${input.listing_id}: ${err.message}`));
  await Sentry.flush(2000);
  return {
    listing_id: input.listing_id,
    current_db_status: input.current_db_status,
    sync_error: err.message,
  };
}

// Unsupported marketplace — log and pass through as error.
const Sentry = require('@sentry/node');
const input = $input.first().json;
const msg = `Status sync skipped: unsupported marketplace '${input.marketplace}' for listing ${input.listing_id}`;
Sentry.captureException(new Error(msg));
await Sentry.flush(2000);
return { listing_id: input.listing_id, current_db_status: input.current_db_status, sync_error: msg };

// Merge status results from OLX and Allegro branches.
const branches = ['OLX Status Check', 'Allegro Status Check', 'Unsupported Marketplace'];
let result = null;
for (const branch of branches) {
  try {
    const items = $(branch).all();
    if (items.length > 0) { result = items[0].json; break; }
  } catch (e) { /* branch not executed */ }
}
if (!result) throw new Error('No marketplace status branch produced output');
return result;

// Update listing status in DB when:
//   a) status_changed=true → update status + last_synced_at + expires_at
//   b) sync_error present → update last_sync_error + last_sync_status='error'
// Skip DB write when status unchanged (reduces write load).

const Sentry = require('@sentry/node');
const https = require('https');

const SUPABASE_URL = $env.SUPABASE_URL;
const SUPABASE_KEY = $env.SUPABASE_SERVICE_ROLE_KEY;

const input = $input.first().json;
const now = new Date().toISOString();

async function supabasePatch(listingId, patchBody) {
  const url = `${SUPABASE_URL}/rest/v1/shop_marketplace_listings?id=eq.${listingId}`;
  const bodyStr = JSON.stringify(patchBody);

  return new Promise((resolve, reject) => {
    const options = {
      method: 'PATCH',
      headers: {
        'apikey': SUPABASE_KEY,
        'Authorization': `Bearer ${SUPABASE_KEY}`,
        'Content-Type': 'application/json',
        'Prefer': 'return=minimal',
      },
    };
    const req = https.request(url, options, (res) => {
      let data = '';
      res.on('data', (chunk) => data += chunk);
      res.on('end', () => resolve({ status: res.statusCode, body: data }));
    });
    req.on('error', reject);
    req.write(bodyStr);
    req.end();
  });
}

try {
  if (input.sync_error) {
    // Sync failed — record error on listing
    const patchResult = await supabasePatch(input.listing_id, {
      last_sync_status: 'error',
      last_sync_error: input.sync_error,
      last_synced_at: now,
    });

    if (patchResult.status >= 400) {
      throw new Error(`Failed to record sync error: HTTP ${patchResult.status}`);
    }

    return {
      listing_id: input.listing_id,
      result: 'error_recorded',
      sync_error: input.sync_error,
    };
  }

  if (!input.status_changed) {
    // Status unchanged — update last_synced_at only (lightweight)
    const patchResult = await supabasePatch(input.listing_id, {
      last_sync_status: 'ok',
      last_sync_error: null,
      last_synced_at: now,
    });

    if (patchResult.status >= 400) {
      throw new Error(`Failed to update last_synced_at: HTTP ${patchResult.status}`);
    }

    return {
      listing_id: input.listing_id,
      result: 'no_change',
      status: input.current_db_status,
    };
  }

  // Status changed — update status + sync metadata
  const patch = {
    status: input.new_status,
    last_sync_status: 'ok',
    last_sync_error: null,
    last_synced_at: now,
  };

  if (input.expires_at) {
    patch.expires_at = input.expires_at;
  }

  const patchResult = await supabasePatch(input.listing_id, patch);

  if (patchResult.status >= 400) {
    throw new Error(`Failed to update listing status: HTTP ${patchResult.status}`);
  }

  Sentry.addBreadcrumb({
    message: `Status updated: listing ${input.listing_id} ${input.current_db_status} → ${input.new_status}`,
    level: 'info',
  });

  return {
    listing_id: input.listing_id,
    result: 'status_updated',
    old_status: input.current_db_status,
    new_status: input.new_status,
  };
} catch (err) {
  Sentry.captureException(err);
  await Sentry.flush(2000);
  throw err;
}
